{
  "rules": [
    ".claude/rules/rtl-generation-rules.md"
  ],
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Write|Edit",
        "hooks": [
          {
            "type": "command",
            "command": "jq -r 'if .tool_response.filePath then .tool_response.filePath elif .tool_input.file_path then .tool_input.file_path else empty end' 2>/dev/null | { read -r f; case \"$f\" in /home/qingyu/edaproject/autortl/src/verilog/*.v) echo \"[PostToolUse Lint] $f\"; verilator --lint-only --Wall --Wno-fatal \"$f\" 2>&1 | tee -a /home/qingyu/edaproject/autortl/sim/logs/lint.log || true;; esac; }",
            "timeout": 60,
            "statusMessage": "Running Verilog lint"
          }
        ]
      }
    ],
    "Stop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "echo \"[$(date '+%Y-%m-%d %%H:%M:%S')] Session stopped\" >> /home/qingyu/edaproject/autortl/sim/logs/notification.log",
            "timeout": 10,
            "statusMessage": "Logging session"
          }
        ]
      }
    ],
    "Notification": [
      {
        "matcher": "generation|verification|error|lint",
        "hooks": [
          {
            "type": "command",
            "command": "jq -r '\"[\\(.notification.type)] \\(.notification.message)\"' 2>/dev/null >> /home/qingyu/edaproject/autortl/sim/logs/notification.log || true",
            "timeout": 10
          }
        ]
      }
    ]
  }
}

